import { expect, userEvent, within } from 'storybook/test';
import { Page } from './Page';

const meta = {
  title: 'AI Generated/Complex/Page',
  component: Page,
  parameters: {
    layout: 'fullscreen',
  },
} satisfies Meta<typeof Page>;

