### 7. **Representative Component Files & Provider Requirements**

#### **Shared Context Provider (Required)**

**File: `src/shared.tsx`**
```typescript
import React from 'react';
import * as echarts from 'echarts/core';
import type { SetOptionOpts } from 'echarts/core';

export { echarts };

export type EChartsCore = typeof echarts;

export interface ChartContextValue {
  options: echarts.EChartsCoreOption[];
}

export const defaultSetOptionOpt: SetOptionOpts = {
  notMerge: false,
  lazyUpdate: true,
};

export const ChartContext = React.createContext<ChartContextValue | null>(null);

export const useInitialChartContext = () => {
  const [chartContextValue] = React.useState<ChartContextValue>(() => ({
    options: [],
  }));
  return chartContextValue;
};

export const useChartContext = () => {
  const ctx = React.useContext(ChartContext);
  if (process.env.NODE_ENV === 'development' && !ctx)
    throw new Error('The component should render within ChartContext');
  return ctx!;
};

export function useRegister(fn: (echarts: EChartsCore) => void) {
  const isExecuted = React.useRef(false);
  if (isExecuted.current) return;
  isExecuted.current = true;
  fn(echarts);
}

export type EChartExt = Parameters<(typeof echarts)['use']>[0];

export type Simplify<T> = { [K in keyof T]: T[K] } & {};
```

**Key Points:**
- Uses React Context (`ChartContext`) for passing chart options
- Components must render within `ChartContext.Provider`
- Each chart component initializes its own context using `useInitialChartContext()`

#### **Chart Components** (Example: `src/charts.tsx`)

```typescript
export const BarChart = /*#__PURE__*/ defineChart<BarSeriesOption | GridComponentOption>([
  EChartBarChart,
  GridComponent,
]);

export const LineChart = /*#__PURE__*/ defineChart<LineSeriesOption | GridComponentOption>([
  EChartLineChart,
  GridComponent,
]);

export const PieChart = /*#__PURE__*/ defineChart<PieSeriesOption>([EChartPieChart]);
```

Each chart:
- Creates an ECharts instance on mount via `echarts.init()`
- Provides `ChartContext.Provider` for nested components
- Registers chart extensions automatically
- Disposes chart on unmount

#### **Component Components** (Example: `src/components.tsx`)

Components like `<Legend>`, `<Tooltip>`, `<DataZoom>` etc. are passive - they:
- Use `useChartContext()` to get access to the chart context
- Push their configuration options to `ctx.options` array via `useLayoutEffect`
- Return `null` (they're configuration containers, not visual components)
- Examples:
```typescript
export const Legend = defineComponent<LegendComponentOption>(LegendComponent);
export const Tooltip = defineComponent<TooltipComponentOption>(TooltipComponent);
export const DataZoom = defineComponent<DataZoomComponentOption>(DataZoomComponent);
```

#### **Story Component Example**

**File: `src/stories/Button.tsx`**
```typescript
import './button.css';

export interface ButtonProps {
  primary?: boolean;
  backgroundColor?: string;
  size?: 'small' | 'medium' | 'large';
  label: string;
  onClick?: (() => void) | undefined;
}

export const Button = ({
  primary = false,
  size = 'medium',
  backgroundColor,
  label,
  ...props
}: ButtonProps) => {
  const mode = primary ? 'storybook-button--primary' : 'storybook-button--secondary';
  return (
    <button
      type="button"
      className={['storybook-button', `storybook-button--${size}`, mode].join(' ')}
      style={{ backgroundColor }}
      {...props}
    >
      {label}
    </button>
  );
};
```

